const features = $json.features || [];
const usable = features
  .filter((feature) => feature.geometry && Array.isArray(feature.geometry.coordinates))
  .sort((a, b) => (b.properties?.mag || 0) - (a.properties?.mag || 0));

if (!usable.length) {
  throw new Error('No usable USGS event with coordinates was returned.');
}

const selected = usable[0];
const [longitude, latitude, depthKm] = selected.geometry.coordinates;
const props = selected.properties || {};

return [
  {
    json: {
      disaster: {
        source: 'usgs_earthquake_significant_month',
        id: selected.id,
        title: props.title || 'USGS earthquake event',
        url: props.url,
        occurred_at: props.time ? new Date(props.time).toISOString() : null,
        latitude,
        longitude,
        depth_km: depthKm,
        magnitude: props.mag,
        place: props.place,
        event_type: props.type || 'earthquake'
      },
      feral_intent: {
        project: 'feral',
        mode: 'Disaster-to-Feral + Habitat Mapper',
        browser_sidecar: true,
        art_direction: 'hyperreal animal-viewpoint disaster ecology, near-future speculative realism'
      }
    }
  }
];

if (!$json.ok) {
  throw new Error($json.error || 'feral sidecar failed');
}

return [
  {
    json: {
      run_id: $json.run_id,
      prompt_packet_path: $json.prompt_packet_path,
      browser_use_task_path: $json.browser_use_task_path,
      opencode_task_path: $json.opencode_task_path,
      habitat_feature_count: $json.habitat_feature_count,
      positive_prompt: $json.positive_prompt,
      negative_prompt: $json.negative_prompt,
      review_status: 'needs_human_review_before_comfyui'
    }
  }
];
